function enterCicdSelectionMode(initialId) {
    window.cicdSelectionMode = true;
    document.querySelectorAll('.cicd-check').forEach(cb => cb.classList.remove('hidden'));
    document.querySelectorAll('.cicd-status-icon').forEach(ic => ic.classList.add('hidden'));

    if (initialId) {
        const cb = document.querySelector(`.cicd-check[value="${initialId}"]`);
        if (cb) cb.checked = true;
    }
    toggleCicdFab();
}

function toggleCicdCheck(runId) {
    const cb = document.querySelector(`.cicd-check[value="${runId}"]`);
    if (cb) cb.checked = !cb.checked;
    toggleCicdFab();
}

function toggleCicdFab() {
    const checkedCount = document.querySelectorAll('.cicd-check:checked').length;
    const fab = document.getElementById('cicd-actions-fab');
    if (checkedCount > 0) {
        fab.style.display = 'flex';
    } else {
        fab.style.display = 'none';
        window.cicdSelectionMode = false;
        document.querySelectorAll('.cicd-check').forEach(cb => cb.classList.add('hidden'));
        document.querySelectorAll('.cicd-status-icon').forEach(ic => ic.classList.remove('hidden'));
    }
}

async function deleteSelectedWorkflows() {
    const checked = Array.from(document.querySelectorAll('.cicd-check:checked'));
    if (!checked.length) return;
    if (!confirm(`Permanently delete ${checked.length} workflow runs?`)) return;

    showGlobalToast("Batch deleting runs...");
    try {
        await Promise.all(checked.map(cb => 
            fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'delete_workflow_run', run_id: cb.value })
            })
        ));
        showGlobalToast("Purge complete");
        loadWorkflows();
    } catch(e) { showGlobalToast("Batch delete failed", true); }
}

async function copySelectedWorkflowLogs() {
    const checked = Array.from(document.querySelectorAll('.cicd-check:checked'));
    if (!checked.length) return;

    showGlobalToast("📥 Aggregating logs from multiple runs...");
    let aggregatedLogs = "";

    try {
        for (const cb of checked) {
            const runId = cb.value;
            const runEl = document.querySelector(`div[data-run-id="${runId}"]`);
            const runTitle = runEl?.querySelector('span[style*="font-size:14px"]')?.innerText || runId;

            // Get jobs for this run
            const resJobs = await fetch(CONFIG.funcUrl, { 
                method: 'POST', headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'fetch_workflow_jobs', run_id: runId }) 
            });
            const dataJobs = await resJobs.json();

            aggregatedLogs += `\n${'='.repeat(50)}\nRUN: ${runTitle} (ID: ${runId})\n${'='.repeat(50)}\n`;

            for (const job of (dataJobs.jobs || [])) {
                const resLogs = await fetch(CONFIG.funcUrl, { 
                    method: 'POST', headers: {'Content-Type': 'application/json'}, 
                    body: apiBody({ action: 'fetch_job_logs', job_id: job.id }) 
                });
                const dataLogs = await resLogs.json();
                aggregatedLogs += `\n--- JOB: ${job.name} ---\n${dataLogs.logs || "[No logs found]"}\n`;
            }
        }

        await navigator.clipboard.writeText(aggregatedLogs);
        showGlobalToast("📋 All logs combined and copied!");
    } catch(e) { showGlobalToast("Failed to aggregate logs", true); }
}

